'use client';

import { CloudDownloadIcon, CloudUploadIcon, DownloadIcon, RefreshCwIcon } from 'lucide-react';
import Link from 'next/link';
import type { JSX } from 'react';

import type {
  DatabaseEngineManagedMongoApplication,
  DatabaseEngineManagedMongoDatabase,
  MongoSource,
} from '@/shared/contracts/database';
import { Badge, Button } from '@/shared/ui/primitives.public';

import {
  useDatabaseEngineActionsContext,
  useDatabaseEngineStateContext,
} from '../../context/DatabaseEngineContext';

const SOURCE_LABELS: Record<MongoSource, string> = {
  local: 'Local',
  cloud: 'Cloud',
};

export const buildManagedMongoCrudHref = (
  application: DatabaseEngineManagedMongoApplication,
  source: MongoSource = 'local'
): string =>
  `/admin/databases/engine?view=crud&application=${encodeURIComponent(
    application
  )}&source=${source}`;

const formatBytes = (bytes: number | null): string => {
  if (bytes === null) return 'n/a';
  if (bytes < 1024) return `${bytes} B`;
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getEndpointStatusLabel = (
  endpoint: DatabaseEngineManagedMongoDatabase['local']
): string => {
  if (!endpoint.configured) return 'not configured';
  if (endpoint.reachable === true) return 'ready';
  if (endpoint.reachable === false) return 'unreachable';
  return 'unknown';
};

function DatabaseStats({ database }: { database: DatabaseEngineManagedMongoDatabase }): JSX.Element {
  return (
    <div className='min-w-0 space-y-1'>
      <h3 className='truncate text-sm font-semibold text-white'>{database.label}</h3>
      <p className='text-xs text-gray-400'>
        Local {getEndpointStatusLabel(database.local)} - Cloud {getEndpointStatusLabel(database.cloud)}
      </p>
      <p className='text-xs text-gray-400'>
        Local {database.local.collectionCount.toLocaleString()} collections - {formatBytes(database.local.databaseSizeBytes)}
      </p>
      <p className='text-xs text-gray-400'>
        Cloud {database.cloud.collectionCount.toLocaleString()} collections - {formatBytes(database.cloud.databaseSizeBytes)}
      </p>
    </div>
  );
}

function ActionBtn({
  disabled,
  icon: Icon,
  label,
  onClick,
}: {
  disabled: boolean;
  icon: typeof CloudUploadIcon;
  label: string;
  onClick: () => void;
}): JSX.Element {
  return (
    <Button
      type='button'
      variant={label === 'Backup' || label === 'Pull' ? 'outline' : undefined}
      size='xs'
      disabled={disabled}
      onClick={onClick}
    >
      <Icon className='size-3.5' />
      {label}
    </Button>
  );
}

function DatabaseActionButtons({
  database,
  isActive,
  isBackupDisabled,
  isPushDisabled,
  isPullDisabled,
}: {
  database: DatabaseEngineManagedMongoDatabase;
  isActive: boolean;
  isBackupDisabled: boolean;
  isPushDisabled: boolean;
  isPullDisabled: boolean;
}): JSX.Element {
  const { backupManagedMongo, syncManagedMongo } = useDatabaseEngineActionsContext();

  return (
    <div className='mt-3 flex flex-wrap gap-2'>
      <Button asChild variant={isActive ? 'secondary' : 'outline'} size='xs'>
        <Link href={buildManagedMongoCrudHref(database.application, 'local')}>Local Tables</Link>
      </Button>
      <Button asChild variant={isActive ? 'secondary' : 'outline'} size='xs'>
        <Link href={buildManagedMongoCrudHref(database.application, 'cloud')}>Cloud Tables</Link>
      </Button>
      <ActionBtn
        disabled={isBackupDisabled}
        icon={DownloadIcon}
        label='Backup'
        onClick={() => {
          void backupManagedMongo(database.application);
        }}
      />
      <ActionBtn
        disabled={isPushDisabled}
        icon={CloudUploadIcon}
        label='Push'
        onClick={() => {
          void syncManagedMongo('local_to_cloud', database.application);
        }}
      />
      <ActionBtn
        disabled={isPullDisabled}
        icon={RefreshCwIcon}
        label='Pull'
        onClick={() => {
          void syncManagedMongo('cloud_to_local', database.application);
        }}
      />
    </div>
  );
}

function DatabaseSyncIssue({ issue }: { issue: string | null }): JSX.Element | null {
  if (issue === null || issue === '') return null;
  return (
    <p className='mt-2 line-clamp-2 text-xs text-amber-100' title={issue}>
      {issue}
    </p>
  );
}

function ManagedMongoDatabaseScopeCard({
  activeApplication,
  activeSource,
  backupDisabled,
  database,
  syncDisabled,
}: {
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
  backupDisabled: boolean;
  database: DatabaseEngineManagedMongoDatabase;
  syncDisabled: boolean;
}): JSX.Element {
  const isActive = database.application === activeApplication;
  const isBackupDisabled = backupDisabled || !database.canBackupLocal;
  const isPushDisabled = syncDisabled || !database.canPushToCloud;
  const isPullDisabled = syncDisabled || !database.canPullFromCloud;

  return (
    <div className={`rounded-md border p-3 ${isActive ? 'border-emerald-400/40 bg-emerald-500/10' : 'border-white/10 bg-black/20'}`}>
      <div className='flex flex-wrap items-start justify-between gap-3'>
        <DatabaseStats database={database} />
        <Badge variant={isActive ? 'active' : 'outline'} className='border-white/10 text-xs'>
          {isActive ? `Open ${SOURCE_LABELS[activeSource]}` : 'Available'}
        </Badge>
      </div>
      <DatabaseSyncIssue issue={database.syncIssue} />
      <DatabaseActionButtons
        database={database}
        isActive={isActive}
        isBackupDisabled={isBackupDisabled}
        isPushDisabled={isPushDisabled}
        isPullDisabled={isPullDisabled}
      />
    </div>
  );
}

function ManagedMongoPanelHeader({
  backupRoot,
  backupDisabled,
  pullDisabled,
  syncDisabled,
  backupManagedMongo,
  refetchAll,
  syncManagedMongo,
}: {
  backupRoot: string;
  backupDisabled: boolean;
  pullDisabled: boolean;
  syncDisabled: boolean;
  backupManagedMongo: (app: DatabaseEngineManagedMongoApplication | 'all') => Promise<void>;
  refetchAll: () => void;
  syncManagedMongo: (action: 'local_to_cloud' | 'cloud_to_local', app: DatabaseEngineManagedMongoApplication | 'all') => Promise<void>;
}): JSX.Element {
  return (
    <div className='flex flex-wrap items-center justify-between gap-3'>
      <div className='space-y-1'>
        <h2 className='text-sm font-semibold text-white'>Managed MongoDB Files</h2>
        <p className='text-xs text-gray-400'>Backup root: {backupRoot}</p>
      </div>
      <div className='flex flex-wrap gap-2'>
        <Button type='button' variant='outline' size='xs' onClick={refetchAll}>
          <RefreshCwIcon className='size-3.5' /> Refresh
        </Button>
        <Button
          type='button'
          variant='outline'
          size='xs'
          disabled={backupDisabled}
          onClick={() => {
            void backupManagedMongo('all');
          }}
        >
          <DownloadIcon className='size-3.5' /> Backup All
        </Button>
        <Button
          type='button'
          size='xs'
          disabled={syncDisabled}
          onClick={() => {
            void syncManagedMongo('local_to_cloud', 'all');
          }}
        >
          <CloudUploadIcon className='size-3.5' /> Push All
        </Button>
        <Button
          type='button'
          variant='outline'
          size='xs'
          disabled={pullDisabled}
          onClick={() => {
            void syncManagedMongo('cloud_to_local', 'all');
          }}
        >
          <CloudDownloadIcon className='size-3.5' /> Pull All
        </Button>
      </div>
    </div>
  );
}

export function ManagedMongoScopePanel({
  activeApplication,
  activeSource,
}: {
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
}): JSX.Element {
  const { managedMongoDatabases, operationControls, isBackingUpManagedMongo, isSyncingManagedMongo } = useDatabaseEngineStateContext();
  const { backupManagedMongo, refetchAll, syncManagedMongo } = useDatabaseEngineActionsContext();

  if (managedMongoDatabases === undefined) {
    return <div className='rounded-md border border-white/10 bg-black/20 p-3 text-sm text-gray-300'>Loading managed MongoDB files...</div>;
  }

  const { backupRoot, canBackupAllLocal, canPushAllToCloud, canPullAllFromCloud, backupStorage } = managedMongoDatabases;
  const { allowManualBackupRunNow, allowManualFullSync } = operationControls;

  const isBkpActive = isBackingUpManagedMongo || !allowManualBackupRunNow;
  const isSyncActive = isSyncingManagedMongo || !allowManualFullSync;

  const backupDisabled = isBkpActive || !canBackupAllLocal;
  const syncDisabled = isSyncActive || !canPushAllToCloud;
  const pullDisabled = isSyncActive || !canPullAllFromCloud;
  const cardBackupDisabled = isBkpActive || !backupStorage.canWriteBackups;
  const cardSyncDisabled = isSyncActive;

  return (
    <div className='space-y-3 rounded-md border border-white/10 bg-card/30 p-3'>
      <ManagedMongoPanelHeader
        backupRoot={backupRoot}
        backupDisabled={backupDisabled}
        pullDisabled={pullDisabled}
        syncDisabled={syncDisabled}
        backupManagedMongo={backupManagedMongo}
        refetchAll={refetchAll}
        syncManagedMongo={syncManagedMongo}
      />
      <div className='grid gap-3 lg:grid-cols-2 xl:grid-cols-4'>
        {managedMongoDatabases.databases.map((database) => (
          <ManagedMongoDatabaseScopeCard
            key={database.application}
            activeApplication={activeApplication}
            activeSource={activeSource}
            backupDisabled={cardBackupDisabled}
            database={database}
            syncDisabled={cardSyncDisabled}
          />
        ))}
      </div>
    </div>
  );
}

'use client';

import { FormSection } from '@/shared/ui/forms-and-actions.public';
import {
  useDatabaseEngineActionsContext,
  useDatabaseEngineStateContext,
} from '../../context/DatabaseEngineContext';
import {
  ManagedDatabaseCard,
  ManagedMongoSummaryCard,
  isPendingSyncTarget,
} from './DatabaseEngineManagedMongoParts';
import type {
  DatabaseEngineManagedMongoDatabasesResponse,
  DatabaseEngineMongoPendingSyncRequest,
} from '@/shared/contracts/database';

function useManagedMongoState(): {
  managedMongoDatabases: DatabaseEngineManagedMongoDatabasesResponse | undefined;
  isBackingUpManagedMongo: boolean;
  isMongoSyncBusy: boolean;
  isManualBackupAllowed: boolean;
  isManualSyncAllowed: boolean;
  isTogglingManagedMongoSync: boolean;
  pendingMongoSourceSync: DatabaseEngineMongoPendingSyncRequest | null;
} {
  const {
    managedMongoDatabases,
    operationControls,
    isBackingUpManagedMongo,
    isSyncingManagedMongo,
    isTogglingManagedMongoSync,
    isSyncingMongoSources,
    mongoSourceState,
    pendingMongoSourceSync,
  } = useDatabaseEngineStateContext();

  const isManualBackupAllowed = Boolean(operationControls.allowManualBackupRunNow);
  const isManualSyncAllowed = Boolean(operationControls.allowManualFullSync);

  const isMongoSyncBusy =
    isSyncingManagedMongo ||
    isSyncingMongoSources ||
    pendingMongoSourceSync !== null ||
    mongoSourceState?.syncInProgress != null;

  return {
    managedMongoDatabases,
    isBackingUpManagedMongo,
    isMongoSyncBusy,
    isManualBackupAllowed,
    isManualSyncAllowed,
    isTogglingManagedMongoSync,
    pendingMongoSourceSync,
  };
}

export function DatabaseEngineManagedMongoSection(): JSX.Element {
  const { backupManagedMongo, setManagedMongoSyncDisabled, syncManagedMongo, refetchAll } =
    useDatabaseEngineActionsContext();
  const state = useManagedMongoState();

  if (state.managedMongoDatabases === undefined) {
    return (
      <FormSection title='Managed Application Databases'>
        <p className='text-sm text-muted-foreground'>Loading managed database status...</p>
      </FormSection>
    );
  }

  const { managedMongoDatabases: db } = state as { managedMongoDatabases: DatabaseEngineManagedMongoDatabasesResponse };

  const backupDisabled = state.isBackingUpManagedMongo || !state.isManualBackupAllowed || Boolean(db.canBackupAllLocal) === false;
  const syncDisabled = state.isMongoSyncBusy || !state.isManualSyncAllowed || Boolean(db.canPushAllToCloud) === false;
  const pullDisabled = state.isMongoSyncBusy || !state.isManualSyncAllowed || Boolean(db.canPullAllFromCloud) === false;

  const isPushingAll = isPendingSyncTarget(state.pendingMongoSourceSync, 'local_to_cloud', 'all');
  const isPullingAll = isPendingSyncTarget(state.pendingMongoSourceSync, 'cloud_to_local', 'all');

  return (
    <FormSection title='Managed Application Databases' className='space-y-0'>
      <div className='space-y-4'>
        <ManagedMongoSummaryCard
          managedMongoDatabases={db}
          backupDisabled={backupDisabled}
          syncDisabled={syncDisabled}
          pullDisabled={pullDisabled}
          isPushingAll={isPushingAll}
          isPullingAll={isPullingAll}
          refetchAll={refetchAll}
          backupManagedMongo={backupManagedMongo}
          syncManagedMongo={syncManagedMongo}
        />

        {db.databases.map((database) => (
          <ManagedDatabaseCard
            key={database.application}
            database={database}
            backupDisabled={
              state.isBackingUpManagedMongo ||
              !state.isManualBackupAllowed ||
              Boolean(db.backupStorage.canWriteBackups) === false
            }
            syncDisabled={state.isMongoSyncBusy || !state.isManualSyncAllowed}
            isTogglingSync={state.isTogglingManagedMongoSync}
            pendingSync={state.pendingMongoSourceSync}
            backupManagedMongo={backupManagedMongo}
            setManagedMongoSyncDisabled={setManagedMongoSyncDisabled}
            syncManagedMongo={syncManagedMongo}
          />
        ))}
      </div>
    </FormSection>
  );
}

'use client';

/* eslint-disable max-lines */

import type {
  DatabaseEngineManagedMongoApplication,
  DatabaseEngineMongoLastSync,
  DatabaseEngineMongoSyncApplicationTransfer,
  DatabaseEngineMongoSyncBackup,
  DatabaseEngineMongoSyncVerification,
  DatabaseEngineMongoSourceEntry,
  DatabaseEngineMongoSourceState,
  MongoSource,
} from '@/shared/contracts/database';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { Card } from '@/shared/ui/primitives.public';

import type { JSX } from 'react';

const SOURCE_LABELS: Record<MongoSource, string> = {
  local: 'Local Database',
  cloud: 'Cloud Database',
};

const MANAGED_APPLICATIONS: Array<{
  application: DatabaseEngineManagedMongoApplication;
  label: string;
}> = [
  { application: 'geminitestapp', label: 'GeminiTest App' },
  { application: 'studiq', label: 'StudiQ' },
  { application: 'cms-builder', label: 'CMS Builder' },
  { application: 'products', label: 'Products' },
  { application: 'arch', label: 'Milkbar Designers' },
];

const resolveEnvSwitchTarget = (source: MongoSource | null): MongoSource =>
  source === 'cloud' ? 'local' : 'cloud';

const resolveConnectionLabel = (
  reachable: DatabaseEngineMongoSourceEntry['reachable']
): string => {
  if (reachable === false) return 'Unreachable';
  if (reachable === true) return 'Reachable';
  return 'Unknown';
};

const resolveVerificationSummary = (
  lastSync: DatabaseEngineMongoLastSync | null
): string | null => {
  const verification = lastSync?.verification;
  if (verification === null || verification === undefined) return null;

  if (verification.status === 'passed') {
    return `Verified exact mirror (${verification.collectionsCompared} collections)`;
  }

  return `Verification mismatches detected (${verification.mismatches.length})`;
};

const resolveMongoSourceEntryViewModel = (
  entry: DatabaseEngineMongoSourceEntry
): {
  dbName: string | null;
  healthError: string | null;
  activationHint: string | null;
  maskedUri: string;
  connectionLabel: string;
  showActiveBadge: boolean;
  showUnreachableBadge: boolean;
} => ({
  dbName: entry.dbName !== null && entry.dbName !== '' ? entry.dbName : null,
  healthError:
    entry.healthError !== null && entry.healthError !== '' ? entry.healthError : null,
  activationHint:
    !entry.isActive && entry.configured
      ? `To activate this target, add or update MONGODB_ACTIVE_SOURCE_DEFAULT=${entry.source} in the effective env file (.env.local overrides .env in development) and restart the server.`
      : null,
  maskedUri: entry.maskedUri ?? 'Not configured in the effective env yet.',
  connectionLabel: resolveConnectionLabel(entry.reachable),
  showActiveBadge: entry.isActive,
  showUnreachableBadge: entry.reachable === false,
});

const resolveMongoSourceOverviewModel = (
  mongoSourceState: DatabaseEngineMongoSourceState
): {
  activeLabel: string;
  activeDbName: string | null;
  localUri: string;
  cloudUri: string;
  envSelectedSource: MongoSource;
  envSwitchTarget: MongoSource;
} => {
  const activeSource = mongoSourceState.activeSource ?? mongoSourceState.defaultSource;
  const envSelectedSource = mongoSourceState.defaultSource ?? activeSource ?? 'local';
  const activeDbName = (() => {
    const activeEntry =
      activeSource === 'cloud' ? mongoSourceState.cloud : mongoSourceState.local;

    return activeEntry.dbName !== null && activeEntry.dbName !== '' ? activeEntry.dbName : null;
  })();
  const activeLabel =
    activeSource !== null ? `Active source: ${activeSource}` : 'No active Mongo target selected yet.';

  return {
    activeLabel,
    activeDbName,
    localUri: mongoSourceState.local.maskedUri ?? '<configure local uri>',
    cloudUri: mongoSourceState.cloud.maskedUri ?? '<configure cloud uri>',
    envSelectedSource,
    envSwitchTarget: resolveEnvSwitchTarget(envSelectedSource),
  };
};

const resolveLastTransferMetrics = (lastSync: DatabaseEngineMongoLastSync): string[] => {
  const hasValue = (value: string | null): value is string =>
    value !== null && value !== '';
  const applicationTransfers = lastSync.applicationTransfers ?? [];
  const preSyncBackups = lastSync.preSyncBackups ?? [];
  const metrics = [`Synced at: ${lastSync.syncedAt}`, `Direction: ${lastSync.direction}`];

  if (hasValue(lastSync.archivePath)) {
    metrics.push(`Transfer archive: ${lastSync.archivePath}`);
  }
  if (hasValue(lastSync.logPath)) {
    metrics.push(`Transfer log: ${lastSync.logPath}`);
  }
  if (lastSync.verification !== null && lastSync.verification !== undefined) {
    metrics.push(
      `Verification: ${lastSync.verification.status} at ${lastSync.verification.verifiedAt}`
    );
  }

  const verificationSummary = resolveVerificationSummary(lastSync);
  if (verificationSummary !== null) {
    metrics.push(verificationSummary);
  }

  if (applicationTransfers.length > 0) {
    metrics.push(`Application databases synced: ${applicationTransfers.length}`);
  }

  metrics.push(`Pre-sync backups: ${preSyncBackups.length}`);

  return metrics;
};

export type MongoApplicationTransferSummary = {
  application: DatabaseEngineManagedMongoApplication;
  label: string;
  transfer: DatabaseEngineMongoSyncApplicationTransfer | null;
  sourceBackup: DatabaseEngineMongoSyncBackup | null;
  targetBackup: DatabaseEngineMongoSyncBackup | null;
  backupCount: number;
};

const getBackupApplication = (
  backup: DatabaseEngineMongoSyncBackup
): DatabaseEngineManagedMongoApplication =>
  (backup as Partial<DatabaseEngineMongoSyncBackup>).application ?? 'geminitestapp';

const resolveTransferFromVerification = (
  application: DatabaseEngineManagedMongoApplication,
  verification: DatabaseEngineMongoSyncVerification,
  archivePath: string | null,
  logPath: string | null
): DatabaseEngineMongoSyncApplicationTransfer | null => {
  const { sourceDbName, targetDbName } = verification;

  return {
    application,
    sourceDbName,
    targetDbName,
    archivePath: archivePath ?? '',
    logPath: logPath ?? '',
    verification,
  };
};

const resolveApplicationTransfer = (
  lastSync: DatabaseEngineMongoLastSync,
  application: DatabaseEngineManagedMongoApplication
): DatabaseEngineMongoSyncApplicationTransfer | null => {
  const applicationTransfers = lastSync.applicationTransfers ?? [];
  const transferFromList = applicationTransfers.find(
    (item) => item.application === application
  );
  if (transferFromList !== undefined) {
    return transferFromList;
  }

  if (application !== 'geminitestapp') {
    return null;
  }
  if (applicationTransfers.length !== 0) {
    return null;
  }

  const verification = lastSync.verification;
  if (verification === null || verification === undefined) {
    return null;
  }

  return resolveTransferFromVerification(
    application,
    verification,
    lastSync.archivePath,
    lastSync.logPath
  );
};

export const buildMongoApplicationTransferSummaries = (
  lastSync: DatabaseEngineMongoLastSync
): MongoApplicationTransferSummary[] =>
  MANAGED_APPLICATIONS.map(({ application, label }) => {
    const transfer = resolveApplicationTransfer(lastSync, application);
    const backups = (lastSync.preSyncBackups ?? []).filter(
      (backup) => getBackupApplication(backup) === application
    );

    return {
      application,
      label,
      transfer,
      sourceBackup: backups.find((backup) => backup.role === 'source') ?? null,
      targetBackup: backups.find((backup) => backup.role === 'target') ?? null,
      backupCount: backups.length,
    };
  });

const buildTransferStatus = (
  transfer: DatabaseEngineMongoSyncApplicationTransfer | null
): 'Verified' | 'No Transfer' | 'Mismatch' => {
  if (transfer === null) {
    return 'No Transfer';
  }
  if (transfer.verification.status === 'passed') {
    return 'Verified';
  }
  return 'Mismatch';
};

const buildTransferVariant = (
  transfer: DatabaseEngineMongoSyncApplicationTransfer | null
): 'active' | 'pending' | 'error' => {
  if (transfer === null) {
    return 'pending';
  }
  if (transfer.verification.status === 'passed') {
    return 'active';
  }
  return 'error';
};

const fallbackStringValue = (value: string | null, fallback: string): string =>
  value === null || value === '' ? fallback : value;

const MongoTransferSummaryBackupInfo = ({
  backupCount,
  sourceBackupName,
  targetBackupName,
}: {
  backupCount: string;
  sourceBackupName: string;
  targetBackupName: string;
}): JSX.Element => (
  <div className='space-y-1 border-t border-white/10 pt-2 text-xs text-gray-400'>
    <p>Pre-sync backups: {backupCount}</p>
    <p className='truncate font-mono' title={sourceBackupName}>
      Source: {sourceBackupName}
    </p>
    <p className='truncate font-mono' title={targetBackupName}>
      Target: {targetBackupName}
    </p>
  </div>
);

const MongoTransferSummaryNoTransferCard = ({
  summary,
}: {
  summary: MongoApplicationTransferSummary;
}): JSX.Element => (
  <MongoTransferSummaryNoTransferCardBody
    summary={summary}
    backupCount={summary.backupCount.toLocaleString()}
    sourceBackupName={summary.sourceBackup?.backupName ?? 'n/a'}
    targetBackupName={summary.targetBackup?.backupName ?? 'n/a'}
  />
);

const MongoTransferSummaryNoTransferCardBody = ({
  summary,
  backupCount,
  sourceBackupName,
  targetBackupName,
}: {
  summary: MongoApplicationTransferSummary;
  backupCount: string;
  sourceBackupName: string;
  targetBackupName: string;
}): JSX.Element => (
  <div
    key={summary.application}
    className='space-y-2 rounded-md border border-white/10 bg-black/20 p-3'
  >
    <div className='flex items-start justify-between gap-2'>
      <div className='min-w-0 space-y-1'>
        <p className='truncate text-sm font-semibold text-white'>{summary.label}</p>
        <p className='text-[11px] uppercase text-gray-500'>{summary.application}</p>
      </div>
      <StatusBadge status='No Transfer' variant='pending' size='sm' />
    </div>
    <p className='text-xs text-gray-400'>No transfer recorded for this database.</p>
    <MongoTransferSummaryBackupInfo
      backupCount={backupCount}
      sourceBackupName={sourceBackupName}
      targetBackupName={targetBackupName}
    />
  </div>
);

const MongoTransferSummaryTransferCard = ({
  summary,
  transfer,
}: {
  summary: MongoApplicationTransferSummary;
  transfer: DatabaseEngineMongoSyncApplicationTransfer;
}): JSX.Element => (
  <div
    key={summary.application}
    className='space-y-2 rounded-md border border-white/10 bg-black/20 p-3'
  >
    <div className='flex items-start justify-between gap-2'>
      <div className='min-w-0 space-y-1'>
        <p className='truncate text-sm font-semibold text-white'>{summary.label}</p>
        <p className='text-[11px] uppercase text-gray-500'>{summary.application}</p>
      </div>
      <StatusBadge
        status={buildTransferStatus(transfer)}
        variant={buildTransferVariant(transfer)}
        size='sm'
      />
    </div>
    <div className='space-y-1 text-xs text-gray-300'>
      <p>
        {transfer.sourceDbName} -&gt; {transfer.targetDbName}
      </p>
      <p>Collections compared: {transfer.verification.collectionsCompared.toLocaleString()}</p>
      <p className='truncate font-mono text-gray-500' title={transfer.archivePath}>
        {fallbackStringValue(transfer.archivePath, 'No archive path')}
      </p>
      <p className='truncate font-mono text-gray-500' title={transfer.logPath}>
        {fallbackStringValue(transfer.logPath, 'No log path')}
      </p>
    </div>
    <MongoTransferSummaryBackupInfo
      backupCount={summary.backupCount.toLocaleString()}
