'use client';

import { useState, type JSX } from 'react';
import { useSiteContent } from '@/context/SiteContentContext';
import { useLocalizedHref } from '@/context/LocaleContext';

function normalizeLegacyBrand(value: string): string {
  return value.replace(/\bArcana\b/gi, 'STARGATER');
}

export function SiteFooter(): JSX.Element {
  const { footer } = useSiteContent();
  const localizedHref = useLocalizedHref();
  const [newsletterEmail, setNewsletterEmail] = useState('');
  const [newsletterSent, setNewsletterSent] = useState(false);
  const [newsletterSubmitting, setNewsletterSubmitting] = useState(false);
  const brandName = normalizeLegacyBrand(footer.brandName);
  const brandSuffix = normalizeLegacyBrand(footer.brandSuffix);
  const brandDescription = normalizeLegacyBrand(footer.brandDescription);
  const copyright = normalizeLegacyBrand(footer.copyright);

  return (
    <footer
      style={{
        background: 'var(--card-bg)',
        borderTop: '1px solid rgba(var(--accent-rgb),0.1)',
      }}
    >
      {/* Newsletter */}
      <div
        className='px-8 md:px-16 py-16 relative overflow-hidden'
        style={{
          borderBottom: '1px solid rgba(var(--accent-rgb),0.1)',
          background: 'radial-gradient(ellipse 80% 100% at 50% 100%, rgba(var(--accent-rgb),0.12) 0%, transparent 70%)',
        }}
      >
        {/* Dot grid accent */}
        <div className='absolute inset-0 dot-grid opacity-15 pointer-events-none' />

        <div className='max-w-screen-2xl mx-auto flex flex-col md:flex-row items-start md:items-end gap-8 justify-between relative z-10'>
          <div>
            <div className='flex items-center gap-2 mb-1'>
              <span
                className='w-2 h-2 rounded-full flex-shrink-0'
                style={{ background: 'var(--accent)', boxShadow: '0 0 8px var(--accent)', animation: 'neonPulse 2s ease-in-out infinite' }}
              />
              <span className='type-label' style={{ color: 'var(--accent)' }}>{footer.newsletter.eyebrow}</span>
            </div>
            <h3
              className='type-display-md mb-3'
              style={{ color: 'var(--fg)', fontFamily: 'var(--font-display)', fontWeight: 700 }}
            >
              {footer.newsletter.title}
            </h3>
            <p className='type-label max-w-xs' style={{ color: 'var(--muted-teal)', lineHeight: 1.8, letterSpacing: '0.08em' }}>
              {footer.newsletter.body}
            </p>
          </div>

          {newsletterSent ? (
            <p className='type-label' style={{ color: 'var(--accent)', letterSpacing: '0.1em' }}>
              {footer.newsletter.successLabel}
            </p>
          ) : (
            <form
              onSubmit={async (e) => {
                e.preventDefault();
                if (newsletterSubmitting) return;
                setNewsletterSubmitting(true);
                try {
                  await fetch('/api/newsletter', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ email: newsletterEmail }),
                  });
                  setNewsletterSent(true);
                } finally {
                  setNewsletterSubmitting(false);
                }
              }}
              className='flex w-full md:w-auto'
            >
              <input
                type='email'
                required
                value={newsletterEmail}
                onChange={(e) => { setNewsletterEmail(e.target.value); }}
                placeholder={footer.newsletter.emailPlaceholder}
                aria-label={footer.newsletter.emailAriaLabel}
                className='flex-1 md:w-72 px-5 py-3.5 bg-transparent outline-none type-label placeholder:opacity-30'
                style={{
                  border: '1px solid rgba(var(--accent-rgb),0.25)',
                  borderRight: 'none',
                  color: 'var(--fg)',
                  fontFamily: 'var(--font-mono)',
                  background: 'var(--input-bg)',
                }}
              />
              <button
                type='submit'
                disabled={newsletterSubmitting}
                className='btn-primary whitespace-nowrap'
                style={{ padding: '0.75rem 1.75rem', opacity: newsletterSubmitting ? 0.6 : 1 }}
              >
                {footer.newsletter.submitLabel}
              </button>
            </form>
          )}
        </div>
      </div>

      {/* Main grid */}
      <div className='px-8 md:px-16 py-16 max-w-screen-2xl mx-auto'>
        <div className='grid grid-cols-2 md:grid-cols-5 gap-10'>
          {/* Brand column */}
          <div className='col-span-2 md:col-span-2'>
            <div className='flex items-baseline gap-2 mb-4'>
              <span
                style={{
                  fontFamily: 'var(--font-display)',
                  fontSize: '1.4rem',
                  fontWeight: 800,
                  letterSpacing: '0.25em',
                  color: 'var(--accent)',
                  textShadow: '0 0 16px rgba(var(--accent-rgb),0.35)',
                }}
              >
                    {brandName}
              </span>
              <span className='type-label' style={{ color: 'rgba(var(--accent-rgb),0.45)' }}>{brandSuffix}</span>
            </div>
            <p
              className='type-label max-w-xs mb-6'
              style={{ color: 'var(--muted-teal)', lineHeight: 1.9, letterSpacing: '0.08em' }}
            >
              {brandDescription}
            </p>

            {/* Socials */}
            <div className='flex gap-4'>
              {footer.socials.map(({ name, icon, href }) => (
                <a
                  key={name}
                  href={localizedHref(href)}
                  aria-label={name}
                  className='type-label w-8 h-8 flex items-center justify-center transition-all duration-200'
                  style={{
                    color: 'var(--muted-teal)',
                    border: '1px solid rgba(var(--accent-rgb),0.15)',
                  }}
                  onMouseEnter={(e) => {
                    (e.currentTarget as HTMLElement).style.color = 'var(--accent)';
                    (e.currentTarget as HTMLElement).style.borderColor = 'rgba(var(--accent-rgb),0.5)';
                    (e.currentTarget as HTMLElement).style.boxShadow = '0 0 8px rgba(var(--accent-rgb),0.2)';
                  }}
                  onMouseLeave={(e) => {
                    (e.currentTarget as HTMLElement).style.color = 'var(--muted-teal)';
                    (e.currentTarget as HTMLElement).style.borderColor = 'rgba(var(--accent-rgb),0.15)';
                    (e.currentTarget as HTMLElement).style.boxShadow = 'none';
                  }}
                >
                  {icon}
                </a>
              ))}
            </div>
          </div>

          {/* Link columns */}
          {footer.columns.map(({ heading, links }) => (
            <div key={heading}>
              <div className='type-label mb-5' style={{ color: 'var(--accent)', letterSpacing: '0.14em' }}>
                {heading}
              </div>
              <ul className='space-y-3'>
                {links.map((link) => (
                  <li key={link.label}>
                    <a
                      href={localizedHref(link.href)}
                      className='type-label hover:text-[var(--accent)] transition-colors duration-200'
                      style={{ color: 'var(--muted-teal)', letterSpacing: '0.1em' }}
                    >
                      {link.label}
                    </a>
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>

      {/* Bottom bar */}
      <div
        className='px-8 md:px-16 py-5 max-w-screen-2xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4'
        style={{ borderTop: '1px solid rgba(var(--accent-rgb),0.08)' }}
      >
        <span className='type-label' style={{ color: 'rgba(var(--accent-rgb),0.45)' }}>
          {copyright}
        </span>
        <div className='flex gap-8'>
          {footer.legalLinks.map((item) => (
            <a
              key={item.label}
              href={localizedHref(item.href)}
              className='type-label hover:text-[var(--accent)] transition-colors'
              style={{ color: 'rgba(var(--accent-rgb),0.45)' }}
            >
              {item.label}
            </a>
          ))}
        </div>
      </div>
    </footer>
  );
}

/* eslint-disable @typescript-eslint/strict-boolean-expressions,max-lines-per-function,no-empty */
'use client';

import {
  createContext,
  useContext,
  useReducer,
  useEffect,
  useCallback,
  useRef,
  useState,
  type ReactNode,
  type JSX,
} from 'react';
import { useAuth } from '@/context/AuthContext';

export type WishlistItem = {
  productId: string;
  slug: string;
  name: string;
  category: string;
  price?: number;
  priceDisplay: string;
  currencyCode?: string;
  gradient: string;
  imageUrl?: string;
};

type WishlistAction =
  | { type: 'TOGGLE'; item: WishlistItem }
  | { type: 'REMOVE'; productId: string }
  | { type: 'HYDRATE'; items: WishlistItem[] };

function reducer(state: WishlistItem[], action: WishlistAction): WishlistItem[] {
  switch (action.type) {
    case 'TOGGLE': {
      const exists = state.some((i) => i.productId === action.item.productId);
      return exists
        ? state.filter((i) => i.productId !== action.item.productId)
        : [...state, action.item];
    }
    case 'REMOVE':
      return state.filter((i) => i.productId !== action.productId);
    case 'HYDRATE':
      return action.items;
    default:
      return state;
  }
}

const STORAGE_KEY = 'arcana-wishlist';

type WishlistContextValue = {
  items: WishlistItem[];
  total: number;
  isWishlisted: (productId: string) => boolean;
  toggle: (item: WishlistItem) => void;
  remove: (productId: string) => void;
  getCount: (productId: string) => number;
  requestCount: (productId: string) => void;
};

const WishlistContext = createContext<WishlistContextValue | null>(null);

export function WishlistProvider({ children }: { children: ReactNode }): JSX.Element {
  const [items, dispatch] = useReducer(reducer, []);
  const { user } = useAuth();
  const loadedUserIdRef = useRef<string | null>(null);

  // Global wishlist counts cache — visible to all users
  const [countsCache, setCountsCache] = useState<Record<string, number>>({});

  // Batched count fetch — collects product IDs and fires a single request per tick
  const pendingIdsRef = useRef<Set<string>>(new Set());
  const batchTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const flushCountBatch = useCallback(() => {
    const ids = [...pendingIdsRef.current];
    pendingIdsRef.current.clear();
    if (ids.length === 0) return;

    // Split into chunks of 100 (API limit)
    const chunks: string[][] = [];
    for (let i = 0; i < ids.length; i += 100) chunks.push(ids.slice(i, i + 100));

    for (const chunk of chunks) {
      void fetch(`/api/wishlist/counts?productIds=${chunk.join(',')}`)
        .then((res) => (res.ok ? res.json() : null))
        .then((data: { counts?: Record<string, number> } | null) => {
          if (data?.counts) setCountsCache((prev) => ({ ...prev, ...data.counts }));
        })
        .catch(() => {});
    }
  }, []);

  const requestCount = useCallback((productId: string) => {
    if (countsCache[productId] !== undefined) return; // already loaded
    pendingIdsRef.current.add(productId);
    if (batchTimerRef.current) clearTimeout(batchTimerRef.current);
    batchTimerRef.current = setTimeout(flushCountBatch, 50);
  }, [countsCache, flushCountBatch]);

  const getCount = useCallback((productId: string): number => countsCache[productId] ?? 0, [countsCache]);

  // Hydrate from localStorage on first mount
  useEffect(() => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored) dispatch({ type: 'HYDRATE', items: JSON.parse(stored) as WishlistItem[] });
    } catch {}
  }, []);

  // When user logs in, fetch their DB wishlist
  useEffect(() => {
    if (!user) {
      loadedUserIdRef.current = null;
      dispatch({ type: 'HYDRATE', items: [] });
      return;
    }
    if (loadedUserIdRef.current === user.id) return;
    loadedUserIdRef.current = user.id;

    fetch('/api/wishlist')
      .then((res) => (res.ok ? res.json() : null))
      .then((data: { items?: WishlistItem[] } | null) => {
        if (data?.items) dispatch({ type: 'HYDRATE', items: data.items });
      })
      .catch(() => {});
  }, [user]);

  // Persist to localStorage on every change (only when logged in)
  useEffect(() => {
    if (!user) return;
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
    } catch {}
  }, [items, user]);

  // Toggle: requires auth; uses the dedicated toggle endpoint which handles counts atomically
  const toggle = useCallback((item: WishlistItem) => {
    if (!user) return;

    // Optimistic update
    dispatch({ type: 'TOGGLE', item });

    void fetch('/api/wishlist/toggle', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(item),
    })
      .then((res) => (res.ok ? res.json() : null))
      .then((data: { wishlisted?: boolean; count?: number } | null) => {
        if (data?.count !== undefined) {
          setCountsCache((prev) => ({ ...prev, [item.productId]: data.count! }));
        }
      })
      .catch(() => {
        // Revert optimistic update on error
        dispatch({ type: 'TOGGLE', item });
      });
  }, [user]);

  const remove = useCallback((productId: string) => dispatch({ type: 'REMOVE', productId }), []);

  const isWishlisted = useCallback(
    (productId: string) => items.some((i) => i.productId === productId),
    [items],
  );

  return (
    <WishlistContext.Provider value={{ items, total: items.length, isWishlisted, toggle, remove, getCount, requestCount }}>
      {children}
    </WishlistContext.Provider>
  );
}

export function useWishlist(): WishlistContextValue {
  const ctx = useContext(WishlistContext);
  if (!ctx) throw new Error('useWishlist must be inside WishlistProvider');
  return ctx;
}

