import { ObjectId } from 'mongodb';

import { getDb } from './mongodb';

const APPLICATION_ID = 'stargater';
const APPLICATION_NAME = 'Stargater';
const ACTIVITY_LOGS_COLLECTION = 'activity_logs';
const ERROR_LOGS_COLLECTION = 'error_logs';
const SYSTEM_LOGS_COLLECTION = 'system_logs';

type StargaterLogInput = {
  message?: string;
  description?: string;
  type?: string;
  source?: string | null;
  service?: string | null;
  userId?: string | null;
  entityId?: string | null;
  entityType?: string | null;
  path?: string | null;
  method?: string | null;
  statusCode?: number | null;
  requestId?: string | null;
  traceId?: string | null;
  correlationId?: string | null;
  stack?: string | null;
  metadata?: Record<string, unknown> | null;
  context?: Record<string, unknown> | null;
};

const getRuntimeEnvironment = (): string | null =>
  process.env.VERCEL_ENV?.trim() || process.env.NODE_ENV?.trim() || null;

const ensureStargaterObservabilityIndexes = async (): Promise<void> => {
  const db = await getDb();
  await Promise.all([
    db.collection(ACTIVITY_LOGS_COLLECTION).createIndex({ createdAt: -1 }),
    db.collection(ACTIVITY_LOGS_COLLECTION).createIndex({ applicationId: 1, createdAt: -1 }),
    db.collection(ACTIVITY_LOGS_COLLECTION).createIndex({ applicationId: 1, originLogId: 1 }),
    db.collection(ERROR_LOGS_COLLECTION).createIndex({ createdAt: -1 }),
    db.collection(ERROR_LOGS_COLLECTION).createIndex({ applicationId: 1, createdAt: -1 }),
    db.collection(ERROR_LOGS_COLLECTION).createIndex({ applicationId: 1, originLogId: 1 }),
    db.collection(SYSTEM_LOGS_COLLECTION).createIndex({ createdAt: -1 }),
    db.collection(SYSTEM_LOGS_COLLECTION).createIndex({ applicationId: 1, createdAt: -1 }),
    db.collection(SYSTEM_LOGS_COLLECTION).createIndex({ applicationId: 1, originLogId: 1 }),
  ]);
};

export const logStargaterActivity = async (input: StargaterLogInput): Promise<void> => {
  await ensureStargaterObservabilityIndexes();
  const db = await getDb();
  const now = new Date();
  const _id = new ObjectId();
  await db.collection(ACTIVITY_LOGS_COLLECTION).insertOne({
    _id,
    type: input.type ?? 'stargater.activity',
    description: input.description ?? input.message ?? 'Stargater activity',
    userId: input.userId ?? null,
    entityId: input.entityId ?? null,
    entityType: input.entityType ?? null,
    metadata: input.metadata ?? null,
    applicationId: APPLICATION_ID,
    applicationName: APPLICATION_NAME,
    environment: getRuntimeEnvironment(),
    sourceService: input.service ?? input.source ?? 'stargater',
    originDatabase: db.databaseName,
    originCollection: ACTIVITY_LOGS_COLLECTION,
    originLogId: _id.toString(),
    createdAt: now,
    updatedAt: now,
  });
};

export const logStargaterError = async (input: StargaterLogInput): Promise<void> => {
  await ensureStargaterObservabilityIndexes();
  const db = await getDb();
  const now = new Date();
  const _id = new ObjectId();
  const id = _id.toString();
  const doc = {
    _id,
    id,
    level: 'error',
    message: input.message ?? input.description ?? 'Stargater error',
    category: 'STARGATER',
    source: input.source ?? null,
    service: input.service ?? null,
    context: input.context ?? input.metadata ?? null,
    stack: input.stack ?? null,
    path: input.path ?? null,
    method: input.method ?? null,
    statusCode: input.statusCode ?? null,
    requestId: input.requestId ?? null,
    traceId: input.traceId ?? null,
    correlationId: input.correlationId ?? null,
    spanId: null,
    parentSpanId: null,
    userId: input.userId ?? null,
    applicationId: APPLICATION_ID,
    applicationName: APPLICATION_NAME,
    environment: getRuntimeEnvironment(),
    sourceService: input.service ?? input.source ?? 'stargater',
    originDatabase: db.databaseName,
    originCollection: SYSTEM_LOGS_COLLECTION,
    originLogId: id,
    createdAt: now,
    updatedAt: now,
  };

  await Promise.all([
    db.collection(SYSTEM_LOGS_COLLECTION).insertOne(doc),
    db.collection(ERROR_LOGS_COLLECTION).updateOne(
      { applicationId: APPLICATION_ID, originLogId: id },
      { $setOnInsert: doc },
      { upsert: true }
    ),
  ]);
};

import 'server-only';

import { readPayPalProviderSettings } from './providerSettings';

const PAYPAL_LIVE_URL = 'https://api-m.paypal.com';
const PAYPAL_SANDBOX_URL = 'https://api-m.sandbox.paypal.com';

type PayPalConfig = {
  clientId: string;
  clientSecret: string;
  webhookId: string;
  mode: 'sandbox' | 'live';
  enabled: boolean;
  apiUrl: string;
};

function env(name: string): string {
  return process.env[name]?.trim() ?? '';
}

function firstNonEmpty(...values: string[]): string {
  for (const v of values) {
    if (v.length > 0) return v;
  }
  return '';
}

function apiUrlForMode(mode: 'sandbox' | 'live'): string {
  return mode === 'live' ? PAYPAL_LIVE_URL : PAYPAL_SANDBOX_URL;
}

async function getPayPalConfig(): Promise<PayPalConfig> {
  const settings = await readPayPalProviderSettings();
  const mode: 'sandbox' | 'live' =
    settings?.mode ?? (env('PAYPAL_MODE') === 'live' ? 'live' : 'sandbox');
  if (settings !== null && settings.enabled === false) {
    return { clientId: '', clientSecret: '', webhookId: '', mode, enabled: false, apiUrl: apiUrlForMode(mode) };
  }
  return {
    clientId: firstNonEmpty(settings?.clientId ?? '', env('PAYPAL_CLIENT_ID')),
    clientSecret: firstNonEmpty(settings?.clientSecret ?? '', env('PAYPAL_CLIENT_SECRET')),
    webhookId: firstNonEmpty(settings?.webhookId ?? '', env('PAYPAL_WEBHOOK_ID')),
    mode,
    enabled: true,
    apiUrl: apiUrlForMode(mode),
  };
}

async function getAccessToken(config: PayPalConfig): Promise<string> {
  const credentials = Buffer.from(`${config.clientId}:${config.clientSecret}`).toString('base64');
  const res = await fetch(`${config.apiUrl}/v1/oauth2/token`, {
    method: 'POST',
    headers: {
      Authorization: `Basic ${credentials}`,
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: 'grant_type=client_credentials',
    cache: 'no-store',
  });
  if (!res.ok) throw new Error(`PayPal auth failed: ${res.status}`);
  const data = (await res.json()) as { access_token: string };
  return data.access_token;
}

function toDecimalAmount(grosz: number): string {
  return (grosz / 100).toFixed(2);
}

export type PayPalLineItem = {
  name: string;
  unit_amount: { currency_code: string; value: string };
  quantity: string;
};

export type CreatePayPalOrderParams = {
  amount: number;
  currency: string;
  items: PayPalLineItem[];
  description: string;
  extOrderId: string;
  returnUrl: string;
  cancelUrl: string;
};

export type PayPalOrderResult = {
  paypalOrderId: string;
  approveUrl: string;
};

export type CapturePayPalOrderResult = {
  paypalOrderId: string;
  status: string;
};

export async function createPayPalOrder(params: CreatePayPalOrderParams): Promise<PayPalOrderResult> {
  const config = await getPayPalConfig();
  if (!config.enabled || config.clientId === '') throw new Error('PayPal is not configured');

  const token = await getAccessToken(config);
  const amountStr = toDecimalAmount(params.amount);

  const res = await fetch(`${config.apiUrl}/v2/checkout/orders`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
      'PayPal-Request-Id': params.extOrderId,
    },
    body: JSON.stringify({
      intent: 'CAPTURE',
      purchase_units: [
        {
          reference_id: params.extOrderId,
          description: params.description,
          amount: {
            currency_code: params.currency,
            value: amountStr,
            breakdown: { item_total: { currency_code: params.currency, value: amountStr } },
          },
          items: params.items,
        },
      ],
      application_context: {
        return_url: params.returnUrl,
        cancel_url: params.cancelUrl,
        brand_name: 'Stargater',
        user_action: 'PAY_NOW',
        shipping_preference: 'NO_SHIPPING',
      },
    }),
    cache: 'no-store',
  });

  const data = (await res.json()) as {
    id?: string;
    links?: Array<{ rel: string; href: string }>;
    message?: string;
    name?: string;
  };

  if (!res.ok) throw new Error(data.message ?? `PayPal order creation failed: ${res.status}`);

  const approveUrl = data.links?.find((l) => l.rel === 'approve')?.href ?? '';
  return { paypalOrderId: data.id ?? '', approveUrl };
}

export async function capturePayPalOrder(paypalOrderId: string): Promise<CapturePayPalOrderResult> {
  const config = await getPayPalConfig();
  if (!config.enabled || config.clientId === '') throw new Error('PayPal is not configured');

  const token = await getAccessToken(config);
  const res = await fetch(`${config.apiUrl}/v2/checkout/orders/${encodeURIComponent(paypalOrderId)}/capture`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    cache: 'no-store',
  });

  const data = (await res.json()) as {
    id?: string;
    status?: string;
    message?: string;
    name?: string;
  };

  if (!res.ok && res.status !== 422) {
    throw new Error(data.message ?? `PayPal capture failed: ${res.status}`);
  }

  return {
    paypalOrderId: data.id ?? paypalOrderId,
    status: data.status ?? 'DECLINED',
  };
}

export async function verifyPayPalWebhook(
  rawBody: string,
  headers: {
    'paypal-auth-algo'?: string | null;
    'paypal-cert-url'?: string | null;
    'paypal-transmission-id'?: string | null;
    'paypal-transmission-sig'?: string | null;
    'paypal-transmission-time'?: string | null;
  },
): Promise<boolean> {
  try {
    const config = await getPayPalConfig();
    if (!config.enabled || config.webhookId === '') return false;

    const token = await getAccessToken(config);
    const res = await fetch(`${config.apiUrl}/v1/notifications/verify-webhook-signature`, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        auth_algo: headers['paypal-auth-algo'],
        cert_url: headers['paypal-cert-url'],
        client_id: config.clientId,
        webhook_id: config.webhookId,
        webhook_event: JSON.parse(rawBody) as unknown,
        transmission_id: headers['paypal-transmission-id'],
        transmission_sig: headers['paypal-transmission-sig'],
        transmission_time: headers['paypal-transmission-time'],
      }),
      cache: 'no-store',
    });

    const data = (await res.json()) as { verification_status?: string };
    return data.verification_status === 'SUCCESS';
  } catch {
    return false;
  }
}

export async function getPayPalClientId(): Promise<string> {
  const settings = await readPayPalProviderSettings();
  return firstNonEmpty(settings?.clientId ?? '', env('NEXT_PUBLIC_PAYPAL_CLIENT_ID'));
}

export async function getPayPalMode(): Promise<'sandbox' | 'live'> {
  const settings = await readPayPalProviderSettings();
  if (settings?.mode === 'live') return 'live';
  return env('PAYPAL_MODE') === 'live' ? 'live' : 'sandbox';
}

