} from '../shared/KangurMobileUi';

export { getSessionAccentTone } from './profile-tones';

export const formatProfileDate = (value: string | null, locale: 'pl' | 'en' | 'de'): string => {
  const fallback = { de: 'kein Datum', en: 'no date', pl: 'brak daty' }[locale];
  if (!value) return fallback;
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return fallback;
  return parsed.toLocaleDateString(getKangurMobileLocaleTag(locale), { day: '2-digit', month: 'short' });
};

export const formatProfileDateTime = (value: string, locale: 'pl' | 'en' | 'de'): string => {
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return { de: 'kein Datum', en: 'no date', pl: 'brak daty' }[locale];
  return parsed.toLocaleString(getKangurMobileLocaleTag(locale), { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' });
};

export const formatProfileDuration = (value: number): string => {
  const safeValue = Math.max(0, Math.floor(value));
  if (safeValue < 60) return `${safeValue}s`;
  const minutes = Math.floor(safeValue / 60);
  const seconds = safeValue % 60;
  return `${minutes}m ${seconds.toString().padStart(2, '0')}s`;
};

export const getPriorityLabel = (priority: KangurAssignmentPriority, locale: 'pl' | 'en' | 'de'): string => {
  return {
    high: { de: 'Hohe Priorität', en: 'High priority', pl: 'Priorytet wysoki' },
    medium: { de: 'Mittlere Priorität', en: 'Medium priority', pl: 'Priorytet średni' },
    low: { de: 'Niedrige Priorität', en: 'Low priority', pl: 'Priorytet niski' },
  }[priority][locale];
};

export const getPriorityTone = (priority: KangurAssignmentPriority): Tone => {
  if (priority === 'high') return { backgroundColor: '#fef2f2', borderColor: '#fecaca', textColor: '#b91c1c' };
  if (priority === 'medium') return { backgroundColor: '#fffbeb', borderColor: '#fde68a', textColor: '#b45309' };
  return { backgroundColor: '#eff6ff', borderColor: '#bfdbfe', textColor: '#1d4ed8' };
};

export const getMasteryTone = (masteryPercent: number): Tone => {
  if (masteryPercent >= 80) return { backgroundColor: '#ecfdf5', borderColor: '#a7f3d0', textColor: '#047857' };
  if (masteryPercent >= 60) return { backgroundColor: '#fffbeb', borderColor: '#fde68a', textColor: '#b45309' };
  return { backgroundColor: '#fef2f2', borderColor: '#fecaca', textColor: '#b91c1c' };
};

export const getSessionScoreTone = (accuracyPercent: number): Tone => {
  if (accuracyPercent >= 90) return { backgroundColor: '#ecfdf5', borderColor: '#a7f3d0', textColor: '#047857' };
  if (accuracyPercent >= 70) return { backgroundColor: '#fffbeb', borderColor: '#fde68a', textColor: '#b45309' };
  return { backgroundColor: '#fef2f2', borderColor: '#fecaca', textColor: '#b91c1c' };
};

import { resolvePreferredKangurPracticeOperation } from '@kangur/core';
import {
  buildKangurLearnerProfileSnapshot,
  type KangurLearnerRecommendationAction,
  type KangurLearnerProfileSnapshot,
} from '@kangur/core';
import { createDefaultKangurProgressState } from '@kangur/contracts/kangur';
import type { Href } from 'expo-router';
import { useMemo, useSyncExternalStore } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { createKangurParentDashboardHref } from '../parent/parentHref';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { useKangurMobileScoreHistory } from '../scores/useKangurMobileScoreHistory';

type UseKangurMobileLearnerProfileResult = {
  authError: string | null;
  authMode: 'development' | 'learner-session';
  canNavigateToRecommendation: (page: string) => boolean;
  displayName: string;
  getActionHref: (action: KangurLearnerRecommendationAction) => Href | null;
  isAuthenticated: boolean;
  isLoadingAuth: boolean;
  isLoadingScores: boolean;
  recommendationsNote: string;
  refreshScores: () => Promise<void>;
  scoresError: string | null;
  signIn: () => Promise<void>;
  supportsLearnerCredentials: boolean;
  snapshot: KangurLearnerProfileSnapshot;
};

const getKangurMobileProfileDisplayName = (fullName: string | null | undefined, learnerDisplayName: string | null | undefined, fallbackLabel: string): string => {
  const activeLearner = learnerDisplayName?.trim();
  if (activeLearner !== undefined && activeLearner !== '') return activeLearner;
  const userName = fullName?.trim();
  return (userName !== undefined && userName !== '') ? userName : fallbackLabel;
};

const PAGE_HREF_MAP: Record<string, () => Href | null> = {
  LearnerProfile: () => '/profile',
  ParentDashboard: createKangurParentDashboardHref,
};

const getLessonsHref = (query: Record<string, string | string[]> | undefined): Href => {
    const focus = query?.['focus']?.trim();
    return (focus !== undefined && focus !== '') ? { pathname: '/lessons', params: { focus } } : '/lessons';
};

const getGameHref = (query: Record<string, string | string[]> | undefined): Href => {
    const operation = (query?.['operation'] ?? query?.['focus']) as string | undefined;
    const resolved = (resolvePreferredKangurPracticeOperation(operation) as string | undefined) ?? 'mixed';
    return { pathname: '/practice', params: { operation: resolved } };
};

const createKangurMobileActionHref = (action: KangurLearnerRecommendationAction): Href | null => {
  if (action.page === 'Lessons') return getLessonsHref(action.query);
  if (action.page === 'Game') return getGameHref(action.query);
  return PAGE_HREF_MAP[action.page]?.() ?? null;
};

export const useKangurMobileLearnerProfile = (): UseKangurMobileLearnerProfileResult => {
  const { copy, locale } = useKangurMobileI18n();
  const { authError, authMode, isLoadingAuth, session, signIn, supportsLearnerCredentials } = useKangurMobileAuth();
  const { defaultDailyGoalGames, progressStore } = useKangurMobileRuntime();

  const progress = useSyncExternalStore(progressStore.subscribeToProgress, progressStore.loadProgress, createDefaultKangurProgressState);
  const isAuthenticated = session.status === 'authenticated';
  const scoresQuery = useKangurMobileScoreHistory({ enabled: isAuthenticated, limit: 120, sort: '-created_date' });

  const snapshot = useMemo(() => buildKangurLearnerProfileSnapshot({
    progress,
    scores: scoresQuery.scores,
    dailyGoalGames: defaultDailyGoalGames,
    locale,
  }), [defaultDailyGoalGames, locale, progress, scoresQuery.scores]);

  const canNavigateToRecommendation = (page: string): boolean => ['Lessons', 'Game', 'LearnerProfile', 'ParentDashboard'].includes(page);

  const displayName = getKangurMobileProfileDisplayName(session.user?.full_name, session.user?.activeLearner?.displayName, copy({ de: 'Lokaler Modus', en: 'Local mode', pl: 'Tryb lokalny' }));

  const recommendationsNote = copy({
    de: 'Lektionen, Arithmetiktraining und das erste Logikquiz sind schon bereit. Ausgebautere grafische Modi erscheinen hier später.',
    en: 'Lessons, arithmetic practice, and the first logic quiz are already ready. More advanced graphical modes will appear here later.',
    pl: 'Lekcje, trening arytmetyczny i pierwszy quiz logiczny są już gotowe. Bardziej rozbudowane tryby graficzne pojawią się tu później.',
  });

  const scoresError = scoresQuery.error instanceof Error
    ? copy({ de: 'Die Ergebnisse konnten nicht geladen werden.', en: 'Could not load the results.', pl: 'Nie udało się pobrać wyników.' })
    : null;

  return {
    authError, authMode, canNavigateToRecommendation, displayName, getActionHref: createKangurMobileActionHref,
    isAuthenticated, isLoadingAuth, isLoadingScores: isLoadingAuth || scoresQuery.isLoading,
    recommendationsNote, refreshScores: scoresQuery.refresh, scoresError, signIn, supportsLearnerCredentials, snapshot,
  };
};

import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { useState, type PropsWithChildren } from 'react';
import {
  SafeAreaProvider,
  initialWindowMetrics,
} from 'react-native-safe-area-context';

import { KangurMobileAuthProvider } from '../auth/KangurMobileAuthContext';
import { KangurMobileI18nProvider } from '../i18n/kangurMobileI18n';
import { KangurRuntimeProvider } from './KangurRuntimeContext';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { useState, type PropsWithChildren } from 'react';
import {
  SafeAreaProvider,
  initialWindowMetrics,
} from 'react-native-safe-area-context';

import { KangurMobileAuthProvider } from '../auth/KangurMobileAuthContext';
import { KangurMobileI18nProvider } from '../i18n/kangurMobileI18n';
import { KangurRuntimeProvider } from './KangurRuntimeContext';

/**
 * Kangur App Providers
 *
 * Configures the mobile application's global provider stack, including:
 * - QueryClientProvider: TanStack Query for state management and caching.
 * - SafeAreaProvider: React Native safe area handling.
 * - KangurRuntimeProvider: Domain-specific runtime configuration.
 * - KangurMobileI18nProvider: Mobile-specific internationalization.
 * - KangurMobileAuthProvider: Mobile authentication session management.
 */
const createQueryClient = (): QueryClient =>
...

  new QueryClient({
    defaultOptions: {
      mutations: {
        retry: 0,
      },
      queries: {
        retry: 1,
        staleTime: 30_000,
      },
    },
  });

export function KangurAppProviders({
  children,
}: PropsWithChildren): React.JSX.Element {
  const [queryClient] = useState(createQueryClient);

  return (
    <SafeAreaProvider initialMetrics={initialWindowMetrics}>
      <QueryClientProvider client={queryClient}>
        <KangurRuntimeProvider>
          <KangurMobileI18nProvider>
            <KangurMobileAuthProvider>{children}</KangurMobileAuthProvider>
          </KangurMobileI18nProvider>
        </KangurRuntimeProvider>
      </QueryClientProvider>
    </SafeAreaProvider>
  );
}

