import { createKangurResultsHref } from '../scores/resultsHref';
import {
  BASE_TONE,
  ChoiceCardButton,
  INDIGO_TONE,
  SUCCESS_TONE,
  WARNING_TONE,
  type Tone,
} from '../shared/KangurAssessmentUi';
import {
  OutlineLink,
  PrimaryButton,
  SectionCard,
  StatusPill,
} from '../shared/KangurAssessmentUi';
import type { KangurMobileLocale, KangurMobileCopy } from '../i18n/kangurMobileI18n';
