              de: `Richtig: ${correctChoice.label}. ${correctChoice.text}`,
              en: `Correct: ${correctChoice.label}. ${correctChoice.text}`,
              pl: `Poprawnie: ${correctChoice.label}. ${correctChoice.text}`,
